+func writeReviews(out *bytes.Buffer, color Color, reviews []goplaces.Review) {
+	if len(reviews) == 0 {
+		return
+	}
+	out.WriteString(color.Dim("Reviews:"))
+	out.WriteString("\n")
+
+	const maxReviews = 3
+	count := len(reviews)
+	limit := count
+	if count > maxReviews {
+		limit = maxReviews
+	}
+
+	for i := 0; i < limit; i++ {
+		review := reviews[i]
+		line := reviewLine(review)
+		if line == "" {
+			continue
+		}
+		out.WriteString("  - ")
+		out.WriteString(line)
+		out.WriteString("\n")
+	}
+
+	if count > maxReviews {
+		out.WriteString(color.Dim(fmt.Sprintf("  ... %d more", count-maxReviews)))
+		out.WriteString("\n")
+	}
+}
